package main

import (
	"net/http"
	"strings"
)

func (s *Server) registerTemplateRoutes(mux *http.ServeMux) {
	mux.HandleFunc("/api/contracts/templates", func(w http.ResponseWriter, r *http.Request) {
		enableCORS(w, r)
		if r.Method != http.MethodGet {
			w.WriteHeader(http.StatusMethodNotAllowed)
			return
		}
		writeJSON(w, http.StatusOK, []map[string]string{{"name": "SimpleRegistry"}, {"name": "SampleERC20"}})
	})
	mux.HandleFunc("/api/contracts/template/", func(w http.ResponseWriter, r *http.Request) {
		enableCORS(w, r)
		if r.Method != http.MethodGet {
			w.WriteHeader(http.StatusMethodNotAllowed)
			return
		}
		name := strings.TrimPrefix(r.URL.Path, "/api/contracts/template/")
		if name == "" {
			w.WriteHeader(http.StatusBadRequest)
			return
		}
		switch name {
		case "SimpleRegistry":
			writeJSON(w, http.StatusOK, simpleRegistryTemplate())
			return
		case "SampleERC20":
			writeJSON(w, http.StatusOK, sampleERC20Template())
			return
		default:
			w.WriteHeader(http.StatusNotFound)
			return
		}
	})
}

func simpleRegistryTemplate() map[string]interface{} {
	return map[string]interface{}{
		"name": "SimpleRegistry",
		"abi": []interface{}{
			map[string]interface{}{"inputs": []interface{}{map[string]interface{}{"internalType": "bytes32", "name": "key", "type": "bytes32"}, map[string]interface{}{"internalType": "bytes", "name": "value", "type": "bytes"}}, "name": "set", "outputs": []interface{}{}, "stateMutability": "nonpayable", "type": "function"},
			map[string]interface{}{"inputs": []interface{}{map[string]interface{}{"internalType": "bytes32", "name": "key", "type": "bytes32"}}, "name": "get", "outputs": []interface{}{map[string]interface{}{"internalType": "bytes", "name": "", "type": "bytes"}}, "stateMutability": "view", "type": "function"},
			map[string]interface{}{"inputs": []interface{}{}, "name": "owner", "outputs": []interface{}{map[string]interface{}{"internalType": "address", "name": "", "type": "address"}}, "stateMutability": "view", "type": "function"},
			map[string]interface{}{"anonymous": false, "inputs": []interface{}{map[string]interface{}{"indexed": true, "internalType": "bytes32", "name": "key", "type": "bytes32"}, map[string]interface{}{"indexed": false, "internalType": "bytes", "name": "value", "type": "bytes"}, map[string]interface{}{"indexed": true, "internalType": "address", "name": "caller", "type": "address"}}, "name": "ItemSet", "type": "event"},
		},
		"bytecode":               "",
		"constructorArgsExample": []interface{}{},
	}
}

func sampleERC20Template() map[string]interface{} {
	return map[string]interface{}{
		"name":                   "SampleERC20",
		"abi":                    []interface{}{ /* 省略，沿用 main.go 中定义 */ },
		"bytecode":               "",
		"constructorArgsExample": []interface{}{"SampleToken", "STK", "1000000000000000000000000"},
	}
}
